    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) + "/.nuget/packages/xunit.v3.common/3.2.2/lib/netstandard2.0/xunit.v3.common.dll",
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) + "/.nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll",
};

foreach (var dllPath in dlls)
{
    Console.WriteLine($"\n--- {System.IO.Path.GetFileName(dllPath)} ---");
    try {
        var asm = Assembly.LoadFrom(dllPath);
        foreach (var typeName in new[] { "TestCaseOrdererAttribute", "CollectionBehaviorAttribute", "ITestCaseOrderer" })
        {
            var types = asm.GetTypes().Where(t => t.Name == typeName).ToList();
            foreach (var type in types)
            {
                Console.WriteLine($"\n  === {type.FullName} ===");
                if (type.IsInterface)
                {
                    foreach (var m in type.GetMethods())
                    {
                        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType} {p.Name}"));
                        Console.WriteLine($"    {m.ReturnType} {m.Name}({parms})");
                    }
                }
                else
                {
                    foreach (var ctor in type.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
                    {
                        var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType} {p.Name}"));
                        Console.WriteLine($"    ctor({parms})");
                    }
                }
            }
        }
    } catch (Exception ex) {
        Console.WriteLine($"  Error: {ex.Message}");
    }
}
